import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import toast from 'react-hot-toast';
import { Eye, EyeOff } from 'lucide-react';
import { themes } from '../styles/theme';

const LoginPage = () => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [showPass, setShowPass] = useState(false);
  const [loading, setLoading] = useState(false);
  
  const { login } = useAuth();
  const navigate = useNavigate();

  // Use dark theme - Finify emerald colors
  const theme = themes.dark;

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!email || !password) return toast.error('Please enter details.');
    setLoading(true);
    try {
      await login(email, password);
      toast.success('Welcome back to Finify!');
      navigate('/dashboard'); 
    } catch (err) { 
      toast.error('Could not log in.'); 
    } 
    finally { setLoading(false); }
  };

  const styles = {
    container: { 
      minHeight: '100vh', 
      display: 'flex', 
      alignItems: 'center', 
      justifyContent: 'center', 
      padding: '1rem',
      backgroundColor: theme['--bg-color']
    },
    card: { 
        width: '100%', 
        maxWidth: '420px', 
        padding: '2.5rem', 
        backgroundColor: theme['--card-bg'], 
        borderRadius: '16px', 
        border: `1px solid ${theme['--border-color']}`, 
        boxShadow: theme['--shadow-soft']
    },
    title: { 
      fontFamily: 'system-ui, sans-serif', 
      fontSize: '2rem', 
      fontWeight: '700',
      color: theme['--primary-accent'], 
      marginBottom: '0.5rem', 
      textAlign: 'center' 
    },
    subtitle: {
      color: theme['--text-muted'],
      textAlign: 'center',
      marginBottom: '2rem',
      fontSize: '0.875rem'
    },
    inputGroup: { position: 'relative', marginBottom: '1.2rem', width: '100%' },
    label: {
      display: 'block',
      color: theme['--text-secondary'],
      fontSize: '0.75rem',
      fontWeight: '600',
      marginBottom: '0.5rem',
      textTransform: 'uppercase',
      letterSpacing: '0.05em'
    },
    input: { 
        width: '100%', 
        padding: '0.875rem 1rem',
        backgroundColor: theme['--input-bg'], 
        border: `1px solid ${theme['--border-color']}`, 
        borderRadius: '8px', 
        color: theme['--text-main'], 
        fontSize: '0.95rem', 
        outline: 'none',
        boxSizing: 'border-box',
        transition: 'border-color 0.2s, box-shadow 0.2s'
    },
    toggleBtn: { 
        position: 'absolute', 
        right: '12px', 
        top: '60%', 
        transform: 'translateY(-50%)', 
        background: 'none', 
        border: 'none', 
        color: theme['--text-muted'], 
        cursor: 'pointer', 
        display: 'flex', 
        alignItems: 'center',
        zIndex: 10,
        fontSize: '1rem'
    },
    button: { 
        width: '100%', 
        padding: '0.875rem', 
        marginTop: '0.5rem', 
        backgroundColor: theme['--primary-accent'], 
        color: '#000', 
        border: 'none', 
        borderRadius: '8px', 
        fontSize: '1rem',
        fontWeight: '600',
        cursor: 'pointer',
        transition: 'background-color 0.2s, transform 0.1s'
    },
    link: {
      color: theme['--primary-accent'],
      textDecoration: 'none',
      fontWeight: '500'
    }
  };

  return (
    <div style={styles.container}>
      <div style={styles.card}>
        <h2 style={styles.title}>Finify</h2>
        <p style={styles.subtitle}>Sign in to your account</p>
        
        <form onSubmit={handleSubmit}>
          
          <div style={styles.inputGroup}>
            <label style={styles.label}>Email</label>
            <input 
                type="email" 
                placeholder="you@example.com" 
                value={email} 
                onChange={(e) => setEmail(e.target.value)} 
                style={styles.input} 
            />
          </div>
          
          <div style={styles.inputGroup}>
            <label style={styles.label}>Password</label>
            <input 
                type={showPass ? "text" : "password"} 
                placeholder="Enter your password" 
                value={password} 
                onChange={(e) => setPassword(e.target.value)} 
                style={styles.input} 
            />
            <button type="button" onClick={() => setShowPass(!showPass)} style={styles.toggleBtn}>
              {showPass ? <EyeOff size={18} /> : <Eye size={18} />}
            </button>
          </div>
          
          <button type="submit" style={styles.button} disabled={loading}>
            {loading ? 'Signing in...' : 'Sign In'}
          </button>
        </form>
        
        <div style={{textAlign: 'center', marginTop: '1.5rem'}}>
            <Link to="/register" style={styles.link}>Don't have an account? Sign up</Link>
        </div>
      </div>
    </div>
  );
};
export default LoginPage;
